class Solution:
    def maximumBeauty(self, nums: List[int], k: int) -> int:
        nums.sort()
        left = 0
        max_beauty = 0

        for right in range(len(nums)):
            # Move left pointer to ensure nums[left] + k <= nums[right] - k
            while nums[left] + k < nums[right] - k:
                left += 1

            # Update max_beauty with the size of the current window
            max_beauty = max(max_beauty, right - left + 1)

        return max_beauty
